import sys

MOD = 1000000007

def solve_case(r, c, grid):
    dp = [0] * c
    for i in range(r):
        row = grid[i]
        for j in range(c):
            if row[j] == "X":
                dp[j] = 0
            elif i == 0 and j == 0:
                dp[j] = 1
            else:
                v = dp[j]
                if j > 0:
                    v += dp[j - 1]
                dp[j] = v % MOD
    return dp[c - 1]

def main():
    data = sys.stdin.read().split()
    pos = 0
    t = int(data[pos]); pos += 1
    out = []
    for _ in range(t):
        r, c = int(data[pos]), int(data[pos + 1]); pos += 2
        grid = data[pos:pos + r]; pos += r
        out.append(str(solve_case(r, c, grid)))
    sys.stdout.write("\n".join(out) + "\n")

main()
